export const isAuraL10NAvailable = !import.meta.env.SSR && window.$A?.localizationService;
export const getDateTimeErrorMessage = (value) => `datetime component: The value attribute accepts a valid ISO8601 formatted string ` +
    `with timezone offset. but we are getting the ${typeof value} value "${value}" instead.`;
